# Structured lifecycle logging with automatic correlation
import json, logging, time, contextvars, uuid

_ctx = contextvars.ContextVar("log_ctx", default={})

class JsonFormatter(logging.Formatter):
    def format(self, record):
        base = {
            "ts": time.time(),
            "level": record.levelname,
            "stage": getattr(record, "stage", None),
            **_ctx.get(),
            **getattr(record, "fields", {}),
        }
        return json.dumps(base, separators=(",", ":"))

log = logging.getLogger("agent")

def start_request(user_id: str) -> str:
    sid = uuid.uuid4().hex
    _ctx.set({"session_id": sid, "user_hash": hash_user(user_id)})
    log.info("request_received", extra={"stage": "request"})
    return sid

# Stage timing context manager emitting start/end events
from contextlib import contextmanager

REDACT_FIELDS = {"prompt", "completion", "tool_args"}

def redact(fields: dict) -> dict:
    return {k: ("<redacted>" if k in REDACT_FIELDS else v)
            for k, v in fields.items()}

@contextmanager
def stage(name: str, **fields):
    t0 = time.time()
    log.info(f"{name}_start", extra={"stage": name, "fields": redact(fields)})
    outcome = "ok"
    try:
        yield
    except Exception:
        outcome = "error"
        raise
    finally:
        log.info(f"{name}_end", extra={"stage": name, "fields": {
            "latency_ms": round((time.time() - t0) * 1000, 1),
            "outcome": outcome,
        }})

# Usage
with stage("model_call", model="gpt-x", prompt=prompt_text):
    completion = call_model(prompt_text)
with stage("tool_call", tool="search", tool_args=args):
    result = run_tool(args)

# Schema-driven redaction by sensitivity class
SENSITIVITY = {
    "session_id": "internal", "stage": "public", "model": "public",
    "prompt": "user", "completion": "user", "tool_args": "user",
}

def apply_policy(fields: dict) -> dict:
    out = {}
    for k, v in fields.items():
        cls = SENSITIVITY.get(k, "user")  # unknown fields default to strictest
        if cls == "public" or cls == "internal":
            out[k] = v
        elif cls == "user":
            out[k] = "<masked>"
    return out
